const ASODesign = () => {
  const [fastaInput, setFastaInput] = useState('')
  const [params, setParams] = useState({ ...defaultParams })
  const [expanded, setExpanded] = useState<string | false>(false)
  const [loading, setLoading] = useState(false)
  const [resultData, setResultData] = useState<any | null>(null)
  const [error, setError] = useState<string | null>(null)
  const [maxHeight, setMaxHeight] = useState(window.innerHeight - 400)

  // // ASO 序列提取模式：DNA / RNA / CDS，默认 DNA（已注释，改用 source toggle）
  // type SeqMode = 'DNA' | 'RNA' | 'CDS'
  // const [seqMode, setSeqMode] = useState<SeqMode>('DNA')

  // const MODE_COLORS: Record<SeqMode, string> = {
  //   RNA: '#00b894',
  //   DNA: '#3867d6',
  //   CDS: '#f58518'
  // }

  // const handleModeChange = (mode: SeqMode) => {
  //   setSeqMode(mode)
  //   localStorage.setItem('aso_seq_mode', mode)
  //   const raw = localStorage.getItem('highlightRegions')
  //   if (!raw) {
  //     const currentRNA = localStorage.getItem('currentRNA')
  //     if (currentRNA) fetchSequenceByTranscript(currentRNA)
  //     return
  //   }
  //   let highlightData: any
  //   try { highlightData = JSON.parse(raw) } catch { return }
  //   const entries = Array.isArray(highlightData?.DNA) ? highlightData.DNA : []
  //   if (entries.length === 0) {
  //     const currentRNA = localStorage.getItem('currentRNA')
  //     if (currentRNA) fetchSequenceByTranscript(currentRNA)
  //     return
  //   }
  //   fetchSequencesFromDNA(entries)
  // }

  // 序列来源切换：当前转录本 / 当前高亮区域
  type SourceMode = 'transcript' | 'highlight'
  const [sourceMode, setSourceMode] = useState<SourceMode>('transcript')
  const sourceModeRef = useRef<SourceMode>('transcript')
  // 当前高亮区域的摘要信息（用于界面显示）
  const [highlightInfo, setHighlightInfo] = useState<string[]>([])

  /** 切换序列来源 — 仅在用户点击 Step2 按钮时调用 */
  const handleSourceChange = (mode: SourceMode) => {
    setSourceMode(mode)
    sourceModeRef.current = mode
    if (mode === 'highlight') {
      const raw = localStorage.getItem('highlightRegions')
      if (raw) {
        try {
          const highlightData = JSON.parse(raw)
          const entries = Array.isArray(highlightData?.DNA) ? highlightData.DNA : []
          if (entries.length > 0) {
            fetchSequencesFromDNA(highlightData)
            return
          }
        } catch {
          /* ignore */
        }
      }
      // 没有有效 highlight，回退到 transcript
      setSourceMode('transcript')
      sourceModeRef.current = 'transcript'
      setHighlightInfo([])
      const currentRNA = localStorage.getItem('currentRNA')
      if (currentRNA) fetchSequenceByTranscript(currentRNA)
    } else {
      // transcript 模式
      setHighlightInfo([])
      const currentRNA = localStorage.getItem('currentRNA')
      if (currentRNA) fetchSequenceByTranscript(currentRNA)
    }
  }

  /** 从 highlightData 提取 DNA 区间摘要，更新 highlightInfo */
  const updateHighlightInfo = (highlightData: any) => {
    const dnaEntries = Array.isArray(highlightData?.DNA) ? highlightData.DNA : []
    const rnaStrand =
      (Array.isArray(highlightData?.RNA) && highlightData.RNA[0]?.strand) ||
      (Array.isArray(highlightData?.mRNA) && highlightData.mRNA[0]?.strand) ||
      '+'
    const infos = dnaEntries
      .filter((e: any) => e?.chr && typeof e.start === 'number' && typeof e.end === 'number')
      .map((e: any) => `${e.chr}:${e.start}-${e.end}(${rnaStrand})`)
    setHighlightInfo(infos)
  }

  /** 从 DNA genomic 坐标列表提取序列，生成 FASTA
   *  strand 从 RNA/mRNA 字段获取（DNA.strand 始终为 '.'） */
  const fetchSequencesFromDNA = (highlightData: any) => {
    const dnaEntries = Array.isArray(highlightData?.DNA) ? highlightData.DNA : []
    // 从 RNA 或 mRNA 的第一个条目获取 strand（所有 region 共享同一转录本的 strand）
    const rnaStrand =
      (Array.isArray(highlightData?.RNA) && highlightData.RNA[0]?.strand) ||
      (Array.isArray(highlightData?.mRNA) && highlightData.mRNA[0]?.strand) ||
      '+'
    // 更新摘要信息
    updateHighlightInfo(highlightData)

    Promise.all(
      dnaEntries.map(async (entry: any) => {
        const { chr, start, end } = entry
        if (!chr || typeof start !== 'number' || typeof end !== 'number') return ''

        try {
          // 使用 UCSC API 直接获取 genomic 序列（getTranscriptSequence 的 position 模式不适用于 genomic 坐标）
          const ucscUrl = `https://api.genome.ucsc.edu/getData/sequence?genome=hg38&chrom=${chr}&start=${start}&end=${end}`
          console.log('[ASO Design] Fetching sequence from UCSC:', ucscUrl)
          const response = await fetch(ucscUrl)
          if (!response.ok) {
            console.error('[ASO Design] UCSC API error:', response.status, response.statusText)
            return ''
          }
          const data = await response.json()
          let sequence = data?.dna || ''
          if (!sequence) {
            console.error('[ASO Design] UCSC returned no sequence data:', data)
            return ''
          }
          // UCSC 返回小写序列，转为大写
          sequence = sequence.toUpperCase()
          // 如果是负链，取反向互补
          if (rnaStrand === '-') {
            const comp: Record<string, string> = { A: 'T', T: 'A', G: 'C', C: 'G', N: 'N' }
            sequence = sequence
              .split('')
              .reverse()
              .map((b: string) => comp[b] || 'N')
              .join('')
          }
          const fasta_name = `${chr}:${start}-${end}(${rnaStrand})`
          console.log('[ASO Design] Got sequence:', fasta_name, 'length:', sequence.length)
          return `>${fasta_name}\n${sequence}`
        } catch (err) {
          console.error('[ASO Design] Failed to fetch sequence:', err)
          return ''
        }
      })
    ).then((fastaArr) => {
      const fastaStr = fastaArr.filter(Boolean).join('\n')
      console.log('[ASO Design] Generated FASTA:', fastaStr ? `${fastaStr.length} chars` : 'empty')
      if (fastaStr) {
        setFastaInput(fastaStr)
      }
    })
  }

  /** 使用 Transcript name/id 提取序列（当没有 highlight 时的兜底） */
  const fetchSequenceByTranscript = (name: string) => {
    getBrowserRegion({
      transcriptome: 'hg38',
      search: name,
      by: 'auto',
      offset: 0
    }).then((res) => {
      if (res.status === 200) {
        const { region } = res.data.results
        const { chrom, start, end, strand, trans_id, trans_name } = region[0]
        const fasta_name = `${trans_name}|${trans_id}|${chrom}|${start}|${end}|${strand}`

        getTranscriptSequence({
          transcriptome: 'hg38',
          search: name,
          by: 'auto',
          offset: 0
        })
          .then((seqRes) => {
            if (seqRes.status === 200) {
              const sequence = seqRes.data.results.sequence.sequence
              setFastaInput(`>${fasta_name}\n${sequence}`)
            }
          })
          .catch((err) => console.error('Error fetching transcript sequence:', err))
      }
    })
  }

  const { selectedRegions } = useAppSelecter(
    (state) => ({
      selectedRegions: state.rbSettings.selectedRegions
    }),
    shallowEqualApp
  )

  const handleChange = (key: string) => (e: ChangeEvent<HTMLInputElement>) => {
    setParams((prev) => ({ ...prev, [key]: e.target.value }))
  }

  const validateFastaWithReason = (input: string): { valid: boolean; error?: string } => {
    const lines = input.trim().split('\n')
    if (lines.length === 0) {
      return { valid: false, error: 'Input is empty.' }
    }

    let lineNumber = 0
    let inRecord = false
    let hasSeq = false
    const baseRegex = /^[ACGTURYKMSWBDHVN-]+$/i

    for (const line of lines) {
      lineNumber++
      const trimmed = line.trim()

      if (trimmed.startsWith('>')) {
        if (inRecord && !hasSeq) {
          return { valid: false, error: `Missing sequence for header at line ${lineNumber - 1}.` }
        }
        inRecord = true
        hasSeq = false
      } else if (inRecord) {
        if (!baseRegex.test(trimmed)) {
          return {
            valid: false,
            error: `Invalid character(s) in sequence at line ${lineNumber}: "${trimmed}"`
          }
        }
        hasSeq = true
      } else {
        return { valid: false, error: `Line ${lineNumber} must start with '>' for FASTA header.` }
      }
    }

    if (inRecord && !hasSeq) {
      return { valid: false, error: `Final record is missing sequence after header.` }
    }

    return { valid: true }
  }

  const handleDesignClick = async () => {
    const { valid, error: formatError } = validateFastaWithReason(fastaInput)
    if (!valid) {
      setError(`FASTA format error: ${formatError}`)
      setLoading(false)
      return
    }

    setLoading(true)
    setResultData(null)

    const payload = {
      fasta: fastaInput,
      config: params
    }

    try {
      const res = await fetch('https://api.rbrowser.org/api/v1/aso_design/', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      })

      if (!res.ok) throw new Error(`HTTP ${res.status}`)
      const data = await res.json()
      setResultData(data)
    } catch (err) {
      setError((err as Error).message || 'Unknown error')
    } finally {
      setLoading(false)
    }
  }

  const handleReset = () => {
    setParams({ ...defaultParams })
    setFastaInput('')
    setResultData(null)
    setExpanded(false)
  }

  // 粘贴板复制工具
  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text)
  }

  const renderInformation = (info: Record<string, any>) => {
    return Object.entries(info).map(([key, value]) => (
      <Typography key={key} fontSize='sm' mb={0.5}>
        <strong>{key}:</strong>{' '}
        {Array.isArray(value) || typeof value === 'object' ? JSON.stringify(value, null, 2) : String(value)}
      </Typography>
    ))
  }

  const validateInput = (key: string, value: string): boolean => {
    if (key === 'PRIMER_PRODUCT_SIZE_RANGE') return /^\d+-\d+(\s+\d+-\d+)*$/.test(value)
    if (/SIZE/.test(key) || /NUM_RETURN|GC_CLAMP/.test(key)) return /^\d+$/.test(value)
    if (/FLAG|PRIMER_PICK/.test(key)) return /^(0|1)$/.test(value)
    if (key === 'PRIMER_MAX_END_STABILITY') return /^\d+(\.\d+)?$/.test(value)
    return true
  }

  const groupedKeys = {
    General: ['PRIMER_TASK', 'PRIMER_EXPLAIN_FLAG'],
    'Primer Picking': ['PRIMER_PICK_LEFT_PRIMER', 'PRIMER_PICK_INTERNAL_OLIGO', 'PRIMER_PICK_RIGHT_PRIMER'],
    'Primer Size & Product': ['PRIMER_OPT_SIZE', 'PRIMER_MIN_SIZE', 'PRIMER_MAX_SIZE', 'PRIMER_PRODUCT_SIZE_RANGE'],
    Filters: [
      'PRIMER_MAX_NS_ACCEPTED',
      'PRIMER_NUM_RETURN',
      'PRIMER_MAX_POLY_X',
      'PRIMER_GC_CLAMP',
      'PRIMER_MAX_END_STABILITY'
    ]
  }

  useEffect(() => {
    // 初始化：检查是否有 highlight 数据，有则默认用 highlight 模式
    const raw = localStorage.getItem('highlightRegions')
    if (raw) {
      try {
        const highlightData = JSON.parse(raw)
        const entries = Array.isArray(highlightData?.DNA) ? highlightData.DNA : []
        if (entries.length > 0) {
          setSourceMode('highlight')
          sourceModeRef.current = 'highlight'
          fetchSequencesFromDNA(highlightData)
        } else {
          const currentRNA = localStorage.getItem('currentRNA')
          if (currentRNA) fetchSequenceByTranscript(currentRNA)
        }
      } catch {
        const currentRNA = localStorage.getItem('currentRNA')
        if (currentRNA) fetchSequenceByTranscript(currentRNA)
      }
    } else {
      const currentRNA = localStorage.getItem('currentRNA')
      if (currentRNA) fetchSequenceByTranscript(currentRNA)
    }

    // ── 事件监听：仅在数据变化时更新对应模式的 FASTA，绝不自动切换模式 ──

    /** highlightRegions 变化 → 仅当 sourceMode 为 highlight 时更新 FASTA */
    const processHighlightChange = (newValue: string | null) => {
      if (!newValue) return
      // 仅更新摘要信息（无论什么模式都更新 info 以便切换时能看到）
      let highlightData: any
      try {
        highlightData = typeof newValue === 'string' ? JSON.parse(newValue) : newValue
      } catch (err) {
        console.error('[ASO Design] Failed to parse highlightRegions JSON:', err)
        return
      }
      // 始终更新摘要
      updateHighlightInfo(highlightData)
      // 只有当前选择的是 highlight 模式时才更新 FASTA
      if (sourceModeRef.current !== 'highlight') {
        console.log('[ASO Design] highlightRegions changed but mode is transcript, skipping FASTA update')
        return
      }
      const entries = Array.isArray(highlightData?.DNA) ? highlightData.DNA : []
      if (entries.length > 0) {
        console.log('[ASO Design] highlightRegions changed (highlight mode), updating FASTA')
        fetchSequencesFromDNA(highlightData)
      }
    }

    /** currentRNA 变化 → 仅当 sourceMode 为 transcript 时更新 FASTA */
    const processCurrentRNA = (newValue: string | null) => {
      if (!newValue) return
      if (sourceModeRef.current !== 'transcript') {
        console.log('[ASO Design] currentRNA changed but mode is highlight, skipping FASTA update')
        return
      }
      fetchSequenceByTranscript(newValue)
    }

    // 同窗口 localStorage 变化（自定义 storageChange 事件）
    const handleStorageChange = (event: any) => {
      const { key, newValue } = event.detail || {}
      if (key === 'highlightRegions') processHighlightChange(newValue)
      else if (key === 'currentRNA') processCurrentRNA(newValue)
    }
    window.addEventListener('storageChange', handleStorageChange as EventListener)

    // 跨窗口 localStorage 变化（原生 storage 事件）
    const handleNativeStorage = (event: StorageEvent) => {
      if (event.key === 'highlightRegions') processHighlightChange(event.newValue)
      else if (event.key === 'currentRNA') processCurrentRNA(event.newValue)
    }
    window.addEventListener('storage', handleNativeStorage)

    // onStorageChange('rnabrowser-selectedRegions', async (newValue, oldValue) => {
    //   console.log('rnabrowser-selectedRegions changed:', newValue)
    //   if (!newValue) return

    //   let regionData: Record<string, any>
    //   try {
    //     regionData = typeof newValue === 'string' ? JSON.parse(newValue) : newValue
    //   } catch (err) {
    //     console.error('Failed to parse selectedRegions JSON:', err)
    //     return
    //   }

    //   const regions = Object.values(regionData)
    //   const fastaParts: string[] = []

    //   for (const region of regions) {
    //     const {
    //       name,
    //       genome: { chr, start, end },
    //       rna: { strand }
    //     } = region as any

    //     try {
    //       const res = await getTranscriptSequence({
    //         transcriptome: 'hg38',
    //         search: `${chr}:${start}-${end}`,
    //         by: 'position',
    //         offset: 0
    //       })

    //       if (res.status === 200) {
    //         const sequence = res.data.results.sequence.sequence
    //         const fasta_name = `${name}|${chr}|${start}|${end}|${strand}`
    //         fastaParts.push(`>${fasta_name}\n${sequence}`)
    //       } else {
    //         console.error(`Failed to fetch sequence for ${name}:`, res)
    //       }
    //     } catch (err) {
    //       console.error(`Error fetching sequence for ${name}:`, err)
    //     }
    //   }

    //   if (fastaParts.length > 0) {
    //     setFastaInput(fastaParts.join('\n'))
    //     console.log('Fasta input set from selected regions:', fastaParts.join('\n'))
    //   }
    // })

    const handleResize = () => {
      setMaxHeight(window.innerHeight - 500)
    }
    window.addEventListener('resize', handleResize)
    return () => {
      window.removeEventListener('resize', handleResize)
      window.removeEventListener('storageChange', handleStorageChange as EventListener)
      window.removeEventListener('storage', handleNativeStorage)
    }
  }, [])

  useEffect(() => {
    console.log('selectedRegions useEffect', selectedRegions)
    // 初始化参数
    // getBrowserRegion({
    //   transcriptome: 'hg38',
    //   search: newValue,
    //   by: 'tname',
    //   offset: 0
    // }).then((res) => {
    //   if (res.status === 200) {
    //     console.log('getBrowserRegion res', res)
    //     const { region } = res.data.results
    //     const { chrom, start, end, strand, trans_id, trans_name } = region[0]

    //     const fasta_name = `${trans_name}|${trans_id}|${chrom}|${start}|${end}|${strand}`

    //     getTranscriptSequence({
    //       transcriptome: 'hg38',
    //       search: newValue,
    //       by: 'tname',
    //       offset: 0
    //     })
    //       .then((seqRes) => {
    //         if (seqRes.status === 200) {
    //           const sequence = seqRes.data.results.sequence.sequence
    //           setFastaInput(`>${fasta_name}\n${sequence}`)
    //         } else {
    //           console.error('Failed to fetch transcript sequence:', seqRes)
    //         }
    //       })
    //       .catch((err) => {
    //         console.error('Error fetching transcript sequence:', err)
    //       })
    //   }
    // })
  }, [selectedRegions])

  return (
    <>
      <PanelMenu to='/aso_design' name='ASO Design' did='aso_design' panelId='aso-design' />
      <PanelBody>
        <Box sx={{ p: 3 }}>
          {/* 显示输入和设置部分，仅当不在 loading 且无结果时显示 */}
          {!loading && !resultData && (
            <>
              <Typography level='h5' mb={2} fontSize='md'>
                Step 1: Input Sequence (FASTA format)
              </Typography>
              <FormControl sx={{ mb: 4 }}>
                <FormLabel sx={{ fontSize: 'sm' }}>FASTA Sequence</FormLabel>
                <Textarea
                  minRows={6}
                  maxRows={6}
                  placeholder={`>sequence id
ATGCGT...`}
                  value={fastaInput}
                  onChange={(e) => setFastaInput(e.target.value)}
                  sx={{ fontSize: 'xs', py: 0.5 }}
                />
              </FormControl>

              <Box sx={{ mb: 4 }}>
                <Typography level='h5' mb={1.5} fontSize='md'>
                  Step 2: Sequence Source
                </Typography>
                <ButtonGroup variant='outlined' size='sm'>
                  <Button
                    variant={sourceMode === 'transcript' ? 'solid' : 'outlined'}
                    onClick={() => handleSourceChange('transcript')}
                    sx={{
                      minWidth: 120,
                      fontWeight: 600,
                      bgcolor: sourceMode === 'transcript' ? '#3867d6' : 'transparent',
                      color: sourceMode === 'transcript' ? '#fff' : '#3867d6',
                      borderColor: '#3867d6',
                      '&:hover': {
                        bgcolor: sourceMode === 'transcript' ? '#3867d6' : '#3867d618',
                        borderColor: '#3867d6'
                      }
                    }}>
                    Current Transcript
                  </Button>
                  <Button
                    variant={sourceMode === 'highlight' ? 'solid' : 'outlined'}
                    onClick={() => handleSourceChange('highlight')}
                    sx={{
                      minWidth: 120,
                      fontWeight: 600,
                      bgcolor: sourceMode === 'highlight' ? '#00b894' : 'transparent',
                      color: sourceMode === 'highlight' ? '#fff' : '#00b894',
                      borderColor: '#00b894',
                      '&:hover': {
                        bgcolor: sourceMode === 'highlight' ? '#00b894' : '#00b89418',
                        borderColor: '#00b894'
                      }
                    }}>
                    Current Highlight Region
                  </Button>
                </ButtonGroup>
                <Typography level='body-xs' mt={0.5} sx={{ color: 'text.tertiary' }}>
                  Switch between transcript sequence and highlighted region sequence.
                </Typography>
                {sourceMode === 'highlight' && highlightInfo.length > 0 && (
                  <Box sx={{ mt: 1 }}>
                    {highlightInfo.map((info, idx) => (
                      <Typography
                        key={idx}
                        level='body-xs'
                        sx={{ color: 'text.tertiary', fontFamily: 'monospace', fontSize: '11px' }}>
                        Region {idx + 1}: {info}
                      </Typography>
                    ))}
                  </Box>
                )}
                {sourceMode === 'highlight' && highlightInfo.length === 0 && (
                  <Typography level='body-xs' mt={0.5} sx={{ color: 'warning.500', fontStyle: 'italic' }}>
                    No highlight regions available. Please select regions in the Transcript Browser.
                  </Typography>
                )}
              </Box>

              <Accordion
                expanded={expanded === 'settings'}
                onChange={(_, isExpanded) => setExpanded(isExpanded ? 'settings' : false)}>
                <AccordionSummary indicator={<ExpandMore />}>
                  <Tooltip
                    title="We recommend keeping the default settings. Adjust them only if you're familiar with the parameters."
                    variant='solid'
                    placement='top-start'>
                    <Typography level='h5' fontSize='md'>
                      Step 3: Settings (Advanced)
                    </Typography>
                  </Tooltip>
                </AccordionSummary>
                <AccordionDetails>
                  <Box sx={{ maxHeight, overflowY: 'auto', overflowX: 'hidden' }}>
                    {Object.entries(groupedKeys).map(([group, keys]) => (
                      <Box key={group} mt={2}>
                        <Typography level='title-sm' mb={0.5}>
                          {group}
                        </Typography>
                        <Grid container spacing={1.5}>
                          {keys.map((key) => (
                            <Grid xs={12} sm={6} md={4} key={key}>
                              <FormControl size='sm'>
                                <Tooltip title={tooltips[key]} variant='solid' placement='top-start'>
                                  <FormLabel sx={{ fontSize: 'xs', mb: 0.5 }}>{labels[key]}</FormLabel>
                                </Tooltip>
                                <Input
                                  size='sm'
                                  value={params[key]}
                                  onChange={handleChange(key)}
                                  error={!validateInput(key, String(params[key]))}
                                  sx={{ fontSize: '10px', '--Input-minHeight': '26px', py: 0.5 }}
                                />
                              </FormControl>
                            </Grid>
                          ))}
                        </Grid>
                      </Box>
                    ))}
                  </Box>
                </AccordionDetails>
              </Accordion>

              <Box mt={4} display='flex' justifyContent='flex-end' gap={2}>
                <Button
                  size='sm'
                  onClick={handleDesignClick}
                  variant='solid'
                  color='primary'
                  startDecorator={<DoneAllRounded fontSize='small' />}>
                  Design
                </Button>
                <Button
                  sx={{ border: '1px solid #ced7e1' }}
                  size='sm'
                  variant='soft'
                  color='success'
                  startDecorator={<AutoAwesomeRounded fontSize='small' />}
                  onClick={() =>
                    setFastaInput(
                      '>example1\nGTTTTTCTGACAGCTATAAGTTGTTCACAAATAGTGGACTTGGATCTATTCATAGCAGATGGAAAGAGCTTGTATGGCACAGGTGAAAGACACCCAAATTTAAAAAATTAAGGCCAAAAGGAACTGTTGCACCTCCTTCCGAGGTTTGGACCCT\n>example2\nGTTTTTCTGACAGCTATAAGTTGTTCACAAATAGTGGACTTGGA\n>example3\nGTTTTTCTGACAGCTAT'
                    )
                  }>
                  Example
                </Button>
                <Button
                  size='sm'
                  onClick={handleReset}
                  sx={{ border: '1px solid #ced7e1' }}
                  color='neutral'
                  variant='plain'
                  startDecorator={<CancelRounded fontSize='small' />}>
                  Reset
                </Button>
              </Box>
            </>
          )}

          {/* Loading 页面 */}
          {loading && (
            <Box display='flex' justifyContent='center' alignItems='center' minHeight='40vh'>
              <Typography level='body-md'>Designing... Please wait</Typography>
            </Box>
          )}

          {/* 结果显示部分 */}
          {resultData && (
            <>
              <ResultsTable data={resultData.results} />
              <Box mt={4} display='flex' justifyContent='flex-end' gap={2}>
                <Button
                  size='sm'
                  onClick={handleReset}
                  variant='solid'
                  color='primary'
                  startDecorator={<ReplayRounded fontSize='small' />}>
                  Redesign
                </Button>

                {/* <Button
                  size='lg'
                  onClick={handleSave}
                  variant='soft'
                  color='success'
                  startDecorator={<SaveRounded />}
                  sx={{ border: '1px solid #ced7e1' }}>
                  Save
                </Button> */}
              </Box>
            </>
          )}
        </Box>

        {/* error snackbar */}
        {error && (
          <Snackbar
            open
            color='danger'
            variant='outlined'
            autoHideDuration={5000}
            onClose={() => setError(null)}
            anchorOrigin={{ vertical: 'top', horizontal: 'center' }}>
            <Box display='flex' alignItems='center' gap={1} sx={{ fontSize: 'sm' }}>
              <ErrorOutlineRoundedIcon color='error' fontSize='small' />
              <strong>Error:</strong> {error}
            </Box>
          </Snackbar>
        )}
      </PanelBody>
    </>
  )
}

export default ASODesign
